SELECT C.*, ( SELECT COUNT(*) FROM "TB_CLUB_MEMBER" CM WHERE CM."CLUB_NUM" = C."CLUB_NUM" ) AS "CURRENT_MEMBER"
FROM "TB_CLUB" C
C."CLUB_CATEGORY" = #{clubCategory}
ORDER BY C."CLUB_NUM" ASC
LIMIT #{perPage} OFFSET #{startNum}

